		// #endif
		copyText(text) {
			let str = '';
			if (text) {
				str = text;
			} else {
				this.customForm.map((e) => {
					if (e.label !== 'img') {
						str += e.title + e.value;
					}
				});
			}
			uni.setClipboardData({
				data: str
			});
