		/**
		 * жү“з”өиҜқ
		 */
		goTel: function () {
			uni.makePhoneCall({
				phoneNumber: this.orderInfo.delivery_id
			});
		},
		/**
		 * и®ҫзҪ®еә•йғЁжҢүй’®
		 *
		 */
		getOrderStatus: function () {
			let orderInfo = this.orderInfo || {},
				_status = orderInfo._status || {
					_type: 0
				},
				status = {};
			let type = parseInt(_status._type),
				delivery_type = orderInfo.delivery_type,
				seckill_id = orderInfo.seckill_id ? parseInt(orderInfo.seckill_id) : 0,
				bargain_id = orderInfo.bargain_id ? parseInt(orderInfo.bargain_id) : 0,
				discount_id = orderInfo.discount_id ? parseInt(orderInfo.discount_id) : 0,
				combination_id = orderInfo.combination_id ? parseInt(orderInfo.combination_id) : 0;
			status = {
				type: type == 9 ? -9 : type,
				class_status: 0
			};
			if (type == 1 && combination_id > 0) status.class_status = 1; //жҹҘзңӢжӢјеӣў
			if (type == 2 && delivery_type == 'express') status.class_status = 2; //жҹҘзңӢзү©жөҒ
			if (type == 2) status.class_status = 3; //зЎ®и®Өж”¶иҙ§
			if (type == 4 || type == 0) status.class_status = 4; //еҲ йҷӨи®ўеҚ•
			if (!seckill_id && !bargain_id && !combination_id && !discount_id && !orderInfo.type && (type == 3 || type == 4)) status.class_status = 5; //еҶҚж¬Ўиҙӯд№°
			this.$set(this, 'status', status);
		},
