		 * еҶҚжӯӨиҙӯд№°
		 *
		 */
		goOrderConfirm: function () {
			let that = this;
			orderAgain(that.orderInfo.order_id)
				.then((res) => {
					return uni.navigateTo({
						url: '/pages/goods/order_confirm/index?new=1&cartId=' + res.data.cateId
					});
				})
				.catch((err) => {
					return that.$util.Tips({
						title: err
					});
				});
		},
		confirmOrder(orderId) {
			let that = this;
			// #ifdef MP
			if (wx.openBusinessView && this.orderInfo.order_shipping_open && this.orderInfo.trade_no && this.orderInfo.uid == this.orderInfo.pay_uid) {
				uni.showLoading({
					title: this.$t(`еҠ иҪҪдёӯ`)
				});
				wx.openBusinessView({
					businessType: 'weappOrderConfirm',
					extraData: {
						transaction_id: this.orderInfo.trade_no
					},
					success() {},
					fail(err) {
						uni.hideLoading();
						return that.$util.Tips({
							title: err.errMsg
						});
					},
					complete() {
						uni.hideLoading();
					}
				});
			} else {
				this.defaultTake(orderId);
			}
			// #endif
			// #ifndef MP
			this.defaultTake(orderId);
			// #endif
		},
		defaultTake(orderId) {
			let that = this;
			uni.showModal({
				title: that.$t(`зЎ®и®Өж”¶иҙ§`),
				content: that.$t(`дёәдҝқйҡңжқғзӣҠпјҢиҜ·ж”¶еҲ°иҙ§зЎ®и®Өж— иҜҜеҗҺпјҢеҶҚзЎ®и®Өж”¶иҙ§`),
				success: (res) => {
					if (res.confirm) {
						orderTake(orderId ? orderId : that.order_id)
							.then((res) => {
								return that.$util.Tips(
									{
										title: that.$t(`ж“ҚдҪңжҲҗеҠҹ`),
										icon: 'success'
									},
									function () {
										that.getOrderInfo();
									}
								);
							})
							.catch((err) => {
								return that.$util.Tips({
									title: err
								});
							});
					}
				}
			});
		},
		/**
		 *
		 * еҲ йҷӨи®ўеҚ•
		 */
		delOrder() {
			let that = this;
			uni.showModal({
				title: this.$t(`еҲ йҷӨи®ўеҚ•`),
				content: this.$t(`зЎ®е®ҡеҲ йҷӨиҜҘи®ўеҚ•`),
				success: (res) => {
					if (res.confirm) {
						(that.isReturn ? refundOrderDel : orderDel)(that.order_id)
							.then((res) => {
								if (that.status.type == -2) {
									return that.$util.Tips(
										{
											title: that.$t(`еҲ йҷӨжҲҗеҠҹ`),
											icon: 'success'
										},
										{
											tab: 5,
											url: '/pages/users/user_return_list/index'
										}
									);
								} else {
									return that.$util.Tips(
										{
											title: that.$t(`еҲ йҷӨжҲҗеҠҹ`),
											icon: 'success'
										},
										{
											tab: 5,
											url: '/pages/goods/order_list/index'
										}
									);
								}
							})
							.catch((err) => {
								return that.$util.Tips({
									title: err
								});
							});
					} else if (res.cancel) {
						return that.$util.Tips({
							title: that.$t(`е·ІеҸ–ж¶Ҳ`)
						});
					}
				}
			});
		},
		cancelOrder() {
			let self = this;
			uni.showModal({
				title: this.$t(`жҸҗзӨә`),
				content: this.$t(`зЎ®и®ӨеҸ–ж¶ҲиҜҘи®ўеҚ•`),
				success: function (res) {
					if (res.confirm) {
						orderCancel(self.orderInfo.order_id)
							.then((data) => {
								// #ifndef MP
								self.$util.Tips(
									{
										title: data.msg
									},
									{
										tab: 3
									}
								);
								// #endif
								// #ifdef MP
								self.$util.Tips(
									{
										title: data.msg
									},
									'/pages/goods/order_list/index'
								);
								// #endif
							})
							.catch(() => {
								self.getOrderInfo();
							});
					} else if (res.cancel) {
					}
				}
			});
		}
	}
};
